function executeKeyImport() {
    const raw = document.getElementById('key-import-area').value;
    if (!raw.trim()) return;

    // 1. Smart Split: Use 'AIza' as the start of record delimiter
    // This handles cases where keys are stuck together without spaces or newlines
    const parts = raw.split('AIza');
    const keys = parts
        .filter(p => p.length > 10) // Filter out the empty first part or noise
        .map(p => 'AIza' + p.trim().split(/\s|\n|,|"|'|;/)[0]); // Re-attach prefix and take the continuous string segment

    if (keys.length === 0) return showGlobalToast("No valid Gemini keys found", true);

    // 2. Generate SQL Insert
    const values = keys.map((k, i) => `('gemini', '${k}', 'Imported Key ${i + 1}')`).join(',\n    ');
    const sql = `-- KEY IMPORT: Generated by Smart Importer\n-- Extracted ${keys.length} keys from raw source\nINSERT INTO public.api_keys (service, api_key, name)\nVALUES\n    ${values};`;

    document.getElementById('key-importer-overlay').style.display = 'none';
    transitionToSql(sql);
}

ops.replace_with:
function handleKeyImportInput(el) {
    const raw = el.value;
    if (!raw.includes('AIza')) return;

    // Extract all instances starting with AIza followed by alphanumeric characters
    const matches = raw.match(/AIza[a-zA-Z0-9_-]+/g);
    if (matches) {
        const uniqueKeys = [...new Set(matches)];
        const structured = uniqueKeys.join('\n');

        // Only update if the content has actually changed to avoid cursor jumping
        if (el.value !== structured) {
            el.value = structured;
            showGlobalToast(`✨ Detected ${uniqueKeys.length} keys`);
        }
    }
}

