if (tool_results && tool_results.length > 0) {
  // 1. Find the last AI message (the function call) to maintain turn order
  const { data: lastAiMsg } = await supabase.from('conduit_chat_history').select('content').eq('session_id', session_id).eq('sender', 'ai').order('created_at', { ascending: false }).limit(1).single();

  if (lastAiMsg) {
    try {
       const lastAiObj = JSON.parse(lastAiMsg.content);
       contents.push({ role: 'model', parts: lastAiObj.parts || [] });
    } catch(e) { /* ignore fallback */ }
  }

  contents.push({
    role: 'user', // In Gemini API, tool results are often sent as a turn following the model call
    parts: tool_results.map((r: any) => ({ 
      functionResponse: { name: r.name, response: { content: r.content } } 
    }))
  });
} else {
  contents.push({ role: 'user', parts: [{ text: prompt }] });
  await supabase.from('conduit_chat_history').insert({ session_id, sender: 'user', content: prompt });
}

