suspend fun callGeminiEdgeFunction(prompt: String, sessionId: String?): String {
    val python = Python.getInstance()
    val executor = python.getModule("executor")

    val payload = JSONObject().apply {
        put("action", "chat")
        put("prompt", prompt)
        if (sessionId != null) put("session_id", sessionId)
    }

    val raw = callConduitAction(payload)
    println("[DEBUG] Raw Response: $raw")

    try {
        // If the response doesn't look like a JSON Object, return it as a raw error
        if (!raw.trim().startsWith("{")) {
            return "[Non-JSON Response] $raw"
        }

        val jsonResp = JSONObject(raw)

        // Handle explicit error from Edge Function
        if (jsonResp.has("error")) {
            val errMsg = jsonResp.getString("error")
            println("[ERROR] Server side error: $errMsg")
            return "Server Error: $errMsg"
        }

        val candidates = jsonResp.optJSONArray("candidates") ?: return "AI Error: No candidates found. Raw: $raw"
        val content = candidates.getJSONObject(0).optJSONObject("content") ?: return "AI Error: No content found. Raw: $raw"
        val parts = content.optJSONArray("parts") ?: return "AI Error: No parts found. Raw: $raw"

        val responseBlocks = JSONArray()

        for (i in 0 until parts.length()) {
            val part = parts.getJSONObject(i)

            if (part.has("text")) {
                val block = JSONObject()
                block.put("type", "text")
                block.put("content", part.getString("text"))
                responseBlocks.put(block)
            }

            if (part.has("functionCall")) {
                val call = part.getJSONObject("functionCall")
                if (call.getString("name") == "execute_python_code") {
                    val args = call.optJSONObject("args")
                    val code = args?.optString("code") ?: ""
                    if (code.isNotEmpty()) {
                        val executionResult = withContext(Dispatchers.IO) {
                            executor.callAttr("run_code", code).toString() 
                        }
                        val block = JSONObject()
                        block.put("type", "code_execution")
                        block.put("code", code)
                        block.put("result", executionResult)
                        responseBlocks.put(block)
                    }
                }
            }
        }

        return if (responseBlocks.length() > 0) {
            responseBlocks.toString()
        } else {
